const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const s = input[idx++];
  let cnt = 0;
  for (let i = 0; i < s.length; ++i) {
    const ch = s[i];
    if (ch !== '4' && ch !== '7') cnt++;
  }
  results.push(String(cnt));
}
console.log(results.join('\n'));
